#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)b - *(int*)a);
}

int solve(int *A, int *B, int *C, int *D, int n, int k, int m) {
    int *tasks = (int*)malloc(n * sizeof(int));
    int *buttons = (int*)malloc((k + m) * sizeof(int));

    for (int i = 0; i < n; i++) {
        tasks[i] = A[i] - B[i];
    }

    memcpy(buttons, C, k * sizeof(int));
    memcpy(buttons + k, D, m * sizeof(int));

    qsort(tasks, n, sizeof(int), compare);
    qsort(buttons, k + m, sizeof(int), compare);

    int j = 0;

    for (int i = 0; i < k + m; i++) {
        if (j < n && buttons[i] <= tasks[j]) {
            tasks[j] -= buttons[i];
            j++;

            if (j == n) {
                break;
            }
        }
    }

    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += tasks[i];
    }

    free(tasks);
    free(buttons);

    return sum;
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n, k, m;
        scanf("%d %d %d", &n, &k, &m);

        int *A = (int*)malloc(n * sizeof(int));
        int *B = (int*)malloc(n * sizeof(int));
        int *C = (int*)malloc(k * sizeof(int));
        int *D = (int*)malloc(m * sizeof(int));

        for (int i = 0; i < n; i++) scanf("%d", &A[i]);
        for (int i = 0; i < n; i++) scanf("%d", &B[i]);
        for (int i = 0; i < k; i++) scanf("%d", &C[i]);
        for (int i = 0; i < m; i++) scanf("%d", &D[i]);

        printf("%d\n", solve(A, B, C, D, n, k, m));

        free(A);
        free(B);
        free(C);
        free(D);
    }

    return 0;
}

