int solve(vector<int>& A, vector<int>& B, vector<int>& C, vector<int>& D) {
    vector<int> tasks(A.size());
    for (size_t i = 0; i < A.size(); ++i) {
        tasks[i] = A[i] - B[i];
    }
    sort(tasks.rbegin(), tasks.rend());

    vector<int> buttons = C;
    buttons.insert(buttons.end(), D.begin(), D.end());
    sort(buttons.rbegin(), buttons.rend());

    size_t j = 0;

    for (size_t i = 0; i < buttons.size(); ++i) {
        if (j < tasks.size() && buttons[i] <= tasks[j]) {
            tasks[j] -= buttons[i];
            j++;

            if (j == tasks.size()) {
                break;
            }
        }
    }

    return accumulate(tasks.begin(), tasks.end(), 0);
}

