import java.util.*;
public class Main {
    public static int solve(int[] A, int[] B, int[] C, int[] D) {
        int[] tasks = new int[A.length];
        for (int i = 0; i < A.length; i++) {
            tasks[i] = A[i] - B[i];
        }
        Arrays.sort(tasks);
        Arrays.sort(C);
        Arrays.sort(D);

        int[] buttons = new int[C.length + D.length];
        System.arraycopy(C, 0, buttons, 0, C.length);
        System.arraycopy(D, 0, buttons, C.length, D.length);
        Arrays.sort(buttons);

        int j = tasks.length - 1;
        for (int i = buttons.length - 1; i >= 0; i--) {
            if (j < 0) break;
            if (buttons[i] <= tasks[j]) {
                tasks[j] -= buttons[i];
                j--;
            }
        }

        int sum = 0;
        for (int task : tasks) {
            sum += task;
        }
        return sum;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();

        for (int z = 0; z < t; z++) {
