function sln(A, B, C, D) {
    let tasks = A.map((a, i) => a - B[i]).sort((a, b) => b - a);
    let buttons = [...C, ...D].sort((a, b) => b - a);
    let j = 0;

    for (let i = 0; i < buttons.length; i++) {
        if (buttons[i] <= tasks[j]) {
            tasks[j] -= buttons[i];
            j++;

            if (j === tasks.length) {
                break;
            }
        }
    }

    return tasks.reduce((sum, task) => sum + task, 0);
}

